  now(), now(), now(),
  '{"provider":"email","providers":["email"]}'::jsonb, '{}'::jsonb,
  false, false,
  '', '', '', '', '', '', '', ''
) on conflict (id) do nothing;

-- email/password ログインに必要な identity
